531	@app.route('/dump', methods=['POST'])
532	@login_required
533	def dump_file():
534	    if 'file' not in request.files:
535	        return jsonify({'error': 'No file provided'}), 400
536	    
537	    file = request.files['file']
538	    if file.filename == '':
539	        return jsonify({'error': 'Empty filename'}), 400
540	    
541	    if not allowed_file(file.filename):
542	        return jsonify({'error': 'File type not allowed'}), 400
543	    
544	    # Check file size
545	    file.seek(0, 2)
546	    file_size = file.tell()
547	    file.seek(0)
548	    
549	    if file_size > MAX_FILE_SIZE:
550	        return jsonify({'error': f'File too large (max {MAX_FILE_SIZE/1024/1024}MB)'}), 400
551	    
552	    # Get metadata
553	    case_id = secure_filename(request.form.get('case_id', 'unknown'))
554	    category = request.form.get('category', 'uncategorized')
555	    source = request.form.get('source', 'unknown')
556	    notes = request.form.get('notes', '')
557	    
558	    # Generate safe filename
559	    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
560	    original_name = secure_filename(file.filename)
561	    file_id = str(uuid.uuid4())[:8]
562	    
563	    # Create case folder structure
564	    case_folder = os.path.join(UPLOAD_FOLDER, case_id, category)
565	    os.makedirs(case_folder, exist_ok=True)
566	    
567	    # Save file
568	    saved_name = f"{timestamp}_{file_id}_{original_name}"
569	    filepath = os.path.join(case_folder, saved_name)
570	    file.save(filepath)
571	    
572	    # Calculate hash
573	    sha256_hash = hashlib.sha256()
574	    with open(filepath, "rb") as f:
575	        for chunk in iter(lambda: f.read(4096), b""):
576	            sha256_hash.update(chunk)
577	    file_hash = sha256_hash.hexdigest()
578	    
579	    # Create metadata
580	    import json
581	    meta = {
582	        'original_name': original_name,
583	        'saved_name': saved_name,
584	        'file_id': file_id,
585	        'case_id': case_id,
586	        'category': category,
587	        'source': source,
588	        'notes': notes,
589	        'sha256': file_hash,
590	        'size': file_size,
591	        'uploaded_by': 'authenticated_user',
592	        'uploaded_at': datetime.now().isoformat(),
593	        'path': filepath
594	    }
595	    
596	    meta_path = os.path.join(case_folder, f"{saved_name}.json")
597	    with open(meta_path, 'w') as f:
598	        json.dump(meta, f, indent=2)
599	    
600	    return jsonify({
601	        'success': True,
602	        'file_id': file_id,
603	        'filename': saved_name,
604	        'original_name': original_name,
605	        'hash': file_hash[:16] + '...',
606	        'size': file_size,
607	        'case': case_id
608	    })
