            },
            'unlimited_apis': ['duckduckgo', 'searx'],
            'total_capacity': f"{limited_total - limited_used}+ searches this month"
        }


# Singleton
_manager = None

def get_search_manager() -> FreeSearchManager:
    """Get singleton search manager"""
    global _manager
    if _manager is None:
        _manager = FreeSearchManager()
    return _manager
